 {"id":"bd-j5u","title":"Implement ResourceTableRenderer for resource registry display","description":"## Purpose and Rationale

Create a renderer that displays registered resources in a beautiful table format using rich_rust. Resources are data endpoints that clients can read, and visualizing them helps developers understand the server's data exposure.

## Background

MCP resources represent data that can be read by clients (like files, database records, API responses). Displaying them in a clear table with their URIs, types, and descriptions makes it easy to understand what data a server exposes.

## Technical Specification

### Core Structure

```rust
// crates/fastmcp-console/src/handlers/resource_table.rs

use rich_rust::{Table, Column, Panel, JustifyMethod, Style, Tree, TreeNode};
use crate::console::FastMcpConsole;
use crate::theme::FastMcpTheme;
use crate::context::DisplayContext;
use fastmcp::resource::ResourceInfo;

/// Renders resource registry as beautiful tables
pub struct ResourceTableRenderer {
    theme: FastMcpTheme,
    context: DisplayContext,
    show_mime_types: bool,
    group_by_prefix: bool,
}

impl ResourceTableRenderer {
    pub fn new(theme: FastMcpTheme, context: DisplayContext) -> Self {
        Self {
            theme,
            context,
            show_mime_types: true,
            group_by_prefix: true,
        }
    }

    /// Render resources as a table
    pub fn render(&self, resources: &[ResourceInfo], console: &FastMcpConsole) {
        if !self.context.should_use_rich() {
            self.render_plain(resources, console);
            return;
        }

        if resources.is_empty() {
            console.print("[dim]No resources registered[/]");
            return;
        }

        let mut table = Table::new()
            .title(format!("📄 Registered Resources ({})", resources.len()))
            .with_column(Column::new("URI").style(self.theme.primary_style()))
            .with_column(Column::new("Description").max_width(40))
            .with_column(Column::new("Type").justify(JustifyMethod::Center));

        if self.show_mime_types {
            table = table.with_column(Column::new("MIME Type"));
        }

        for resource in resources {
            let uri = self.format_uri(&resource.uri);
            let desc = self.truncate(&resource.description, 40);
            let rtype = self.format_resource_type(&resource.resource_type);

            if self.show_mime_types {
                let mime = resource.mime_type.as_deref().unwrap_or("unknown");
                table.add_row_cells([&uri, &desc, &rtype, mime]);
            } else {
                table.add_row_cells([&uri, &desc, &rtype]);
            }
        }

        console.print_renderable(&table);
    }

    /// Render resources as a tree grouped by URI prefix
    pub fn render_tree(&self, resources: &[ResourceInfo], console: &FastMcpConsole) {
        if !self.context.should_use_rich() {
            self.render_plain(resources, console);
            return;
        }

        if resources.is_empty() {
            console.print("[dim]No resources registered[/]");
            return;
        }

        // Group resources by first path segment
        let mut groups: std::collections::HashMap<String, Vec<&ResourceInfo>> = 
            std::collections::HashMap::new();

        for resource in resources {
            let prefix = self.extract_prefix(&resource.uri);
            groups.entry(prefix).or_default().push(resource);
        }

        // Build tree
        let mut root = TreeNode::new(format!("📄 Resources ({})", resources.len()));

        for (prefix, group_resources) in &groups {
            let mut group_node = TreeNode::new(format!("[cyan]{}[/] ({})", prefix, group_resources.len()));

            for resource in group_resources {
                let leaf = format!("{} [dim]- {}[/]", 
                    resource.uri.split('/').last().unwrap_or(&resource.uri),
                    self.truncate(&resource.description, 30));
                group_node.add_child(TreeNode::new(leaf));
            }

            root.add_child(group_node);
        }

        let tree = rich_rust::Tree::new(root);
        console.print_renderable(&tree);
    }

    fn format_uri(&self, uri: &str) -> String {
        // Highlight the template parts in URIs like "file://{path}"
        if uri.contains('{') {
            uri.replace('{', "[yellow]{").replace('}', "}[/]")
        } else {
            uri.to_string()
        }
    }

    fn format_resource_type(&self, rtype: &ResourceType) -> String {
        match rtype {
            ResourceType::Static => "Static".to_string(),
            ResourceType::Template => "Template".to_string(),
            ResourceType::Dynamic => "Dynamic".to_string(),
        }
    }

    fn extract_prefix(&self, uri: &str) -> String {
        uri.split('/').next().unwrap_or("root").to_string()
    }

    fn truncate(&self, s: &str, max: usize) -> String {
        if s.len() <= max {
            s.to_string()
        } else {
            format!("{}...", &s[..max - 3])
        }
    }

    fn render_plain(&self, resources: &[ResourceInfo], console: &FastMcpConsole) {
        console.print(&format!("Registered Resources ({})", resources.len()));
        for resource in resources {
            console.print(&format!("  {} - {}", resource.uri, resource.description));
        }
    }
}
```

